from collections import defaultdict

events = [
    {'user_id': 1, 'action': 'click', 'count': 3},
    {'user_id': 2, 'action': 'view', 'count': 5},
    {'user_id': 1, 'action': 'view', 'count': 2},
    {'user_id': 2, 'action': 'click', 'count': 1},
    {'user_id': 1, 'action': 'click', 'count': 4},
]

def aggregate_events(events):
    user_totals = defaultdict(lambda: defaultdict(int))
    for e in events:
        user_totals[e['user_id']][e['action']] += e['count']
    return dict({uid: dict(actions) for uid, actions in user_totals.items()})

result = aggregate_events(events)
print(result)
# {1: {'click': 7, 'view': 2}, 2: {'view': 5, 'click': 1}}

