users = [
    {'id': 1, 'name': 'Alice'},
    {'id': 2, 'name': 'Bob'},
    {'id': 3, 'name': 'Charlie'},
]
orders = [
    {'user_id': 1, 'product': 'Laptop', 'amount': 999},
    {'user_id': 2, 'product': 'Phone', 'amount': 699},
    {'user_id': 2, 'product': 'Tablet', 'amount': 499},
    {'user_id': 4, 'product': 'Watch', 'amount': 299},
]

def merge_by_key(users, orders):
    user_map = {u['id']: u['name'] for u in users}
    result = []
    for o in orders:
        uid = o['user_id']
        result.append({
            'user_name': user_map.get(uid, 'Unknown'),
            'product': o['product'],
            'amount': o['amount'],
        })
    return result

print(merge_by_key(users, orders))

