records = [
    {'name': 'Alice', 'age': 30, 'score': None},
    {'name': None, 'age': None, 'score': 85.5},
    {'name': 'Charlie', 'age': 25, 'score': 92.0},
]

defaults = {'name': 'Unknown', 'age': 0, 'score': 0.0}

def clean_records(records, defaults):
    cleaned = []
    for record in records:
        cleaned_record = {}
        for key, value in record.items():
            cleaned_record[key] = value if value is not None else defaults.get(key, value)
        cleaned.append(cleaned_record)
    return cleaned

result = clean_records(records, defaults)
print(result)
# [{'name': 'Alice', 'age': 30, 'score': 0.0},
#  {'name': 'Unknown', 'age': 0, 'score': 85.5},
#  {'name': 'Charlie', 'age': 25, 'score': 92.0}]

